import { ACCESS_TOKEN_STORAGE_KEY } from 'utils/auth-storage'

export type AuthMode = 'hosted' | 'standalone'

export type RuntimeConfig = {
  authMode: AuthMode
  getAccessToken: () => null | string
}

const createDefaultRuntimeConfig = (): RuntimeConfig => ({
  authMode: 'standalone',
  getAccessToken: () => {
    if (typeof window === 'undefined') return null
    return (
      localStorage.getItem(ACCESS_TOKEN_STORAGE_KEY) ||
      sessionStorage.getItem(ACCESS_TOKEN_STORAGE_KEY)
    )
  },
})

let runtimeConfig = createDefaultRuntimeConfig()

export function getRuntimeConfig() {
  return runtimeConfig
}

export function resetRuntimeConfig() {
  runtimeConfig = createDefaultRuntimeConfig()
}

export function setRuntimeConfig(nextConfig: Partial<RuntimeConfig>) {
  runtimeConfig = {
    ...runtimeConfig,
    ...nextConfig,
  }
}

